(window.webpackJsonp=window.webpackJsonp||[]).push([[8],{229:function(t,e,s){"use strict";s.r(e);var n=s(28),r=Object(n.a)({},(function(){var t=this,e=t.$createElement,s=t._self._c||e;return s("ContentSlotsDistributor",{attrs:{"slot-key":t.$parent.slotKey}},[s("h1",{attrs:{id:"别让同情打扰他人"}},[s("a",{staticClass:"header-anchor",attrs:{href:"#别让同情打扰他人"}},[t._v("#")]),t._v(" 别让同情打扰他人")]),t._v(" "),s("p",[t._v("照片中，一个留着齐耳短发的小女孩手持舀粥勺，笑容灿烂若春日的阳光，尽管周围的环境很简陋，但在笑容里，我们看到的是满满的满足感。")]),t._v(" "),s("p",[t._v("她叫谭嘉雯，她顿顿吃面饼、喝粥配咸菜，她爱笑，她只有9岁，外公是公厕管理员，祖孙二人挤在杭州某公交站对面不到3平米的公厕隔间里。网友的一条微博让她成了红人，引来无数热心的市民，还有架起长枪短炮的媒体。也许，在很多人眼中，小嘉雯的生活可以用窘迫困苦来形容。但小嘉雯自己却不这么认为——“你想过那种穿得好、吃得好的生活吗？ ”“我现在就是在过这种生活啊！ ”这是小嘉雯的回答。童言无忌，相信这是她真实的想法。然而，旁观者的同情与爱心，却如滔滔江水滚滚而来，这突如其来的关注，让祖孙二人无所适从不堪其扰。")]),t._v(" "),s("p",[t._v("“我有工作，我可以养活小家伙。 ”小嘉雯的爷爷不止一次地婉拒了帮助。但仍然有人好心地劝解：“不要紧，我很有钱。 ”这种强加于人的同情和善意让小嘉雯不知所措，笑容不见。虽然，在我们的道德字典里，同情弱者是一种最基本的情感，是天性，是与动物的区别。但是，要知道同情亦是把双刃剑。不要把同情和俯视的怜悯划等号，不要站在道德的制高点，用同情扰乱了他人的生活。每个人的世界观与价值观都不相同，若因为自己不同的观念，而用同情把一个原本对生活充满幻想和希望的小女孩变得敏感、沮丧、处处低人一等的话，则实在是好心办坏事、有违初衷了。")]),t._v(" "),s("p",[t._v("通过同情去理解并且经受别人的痛苦，自己也会内心丰富。虽然，在公厕里安身的祖孙俩生活不尽如人意，但依然食能饱腹、住能挡风避雨。如此看来，世上比他们需要帮助的大有人在。我们的同情和善意不能被盲从所遮蔽。用心感受小嘉雯的笑容和快乐的生活观就好，为何一定要让自己的同情成为他人身上的包袱，为何非要把自己的幸福观、价值观强加给一个乐观开朗的孩子？")]),t._v(" "),s("p",[t._v("如果小嘉雯接受了这样的同情和善意，但这如江水般涌来的关注能持续多久呢？一旦媒体不关注了，人们的热情消减了，人走茶凉，小嘉雯从云端跌落谷底，生活依旧，然而原本的乐观开朗不复存在，岂不悲哉！所以，一个人真心向善，付出真诚即可。在施展好心时，别人可以选择接受，抑或拒绝。有时候，温暖别人的内心，比赠与物质更来得沁人心脾。别让蜂拥而来的关心击碎了孩子纯真的笑脸，孩子的想法远比我们想的简单。也许，我们以为昂贵的玩具才能博得孩子的欢心，但有时一张白纸就能放飞梦想。小嘉雯需要的不是同情和物质给予。比起这些，她更需要一个有父母在身边的完整童年。")]),t._v(" "),s("p",[t._v("同情是“与喜乐的人要同乐；与哀哭的人要同哭”。也就是，当别人遇到喜乐和哀哭的事情时，我们肯站在别人的立场上，肯感受别人所感受的，能快乐别人所快乐的，伤心别人所伤心的。这才叫做同情。")])])}),[],!1,null,null,null);e.default=r.exports}}]);